// === MULTI-PAIR FILTER ===
// Загружаем конфигурацию пар
const pairsConfig = $input.item.json;

// Получаем активные пары из pairs.json
const activePairs = pairsConfig.pairs
  .filter(pair => pair.enabled)
  .map(pair => pair.symbol);

// Извлекаем символ из сообщения Bybit
const message = pairsConfig;
const symbol = message.symbol || message.data?.symbol || '';

// Проверяем, есть ли пара в активном списке
const isActive = activePairs.includes(symbol);

if (!isActive) {
  // Игнорируем неактивные пары
  return [];
}

// Находим настройки для этой пары
const pairSettings = pairsConfig.pairs.find(p => p.symbol === symbol);

// Добавляем настройки в сообщение для downstream нод
return {
  json: {
    ...message,
    _pairSettings: pairSettings,
    _symbol: symbol,
    _timestamp: new Date().toISOString()
  }
};

// === TRADING CONDITIONS ===
const item = $input.item.json;
const settings = item._pairSettings;
const data = item.data || item;

// Пример: проверка объема
const volume24h = data.volume_24h || 0;
const minVolume = settings.filters.min_volume_24h || 0;

if (volume24h < minVolume) {
  return []; // Недостаточный объем
}

// Пример: проверка волатильности
const volatility = data.price_change_pct_24h || 0;
const maxVolatility = settings.filters.volatility_max_pct || 100;

if (Math.abs(volatility) > maxVolatility) {
  return []; // Слишком высокая волатильность
}

// Проверяем лимит дневных trades
const dailyTrades = item._dailyTrades || 0;
const maxDaily = settings.risk.max_daily_trades || 999;

if (dailyTrades >= maxDaily) {
  return []; // Достигнут дневной лимит
}

// Все условия выполнены — передаем дальше
return {
  json: {
    ...item,
    _conditionsPassed: true,
    _validatedAt: new Date().toISOString()
  }
};

// === SIGNAL GENERATION ===
const item = $input.item.json;
const settings = item._pairSettings;
const symbol = item._symbol;

// Пример простой логики сигналов (замените на свою стратегию)
const price = item.price || item.last_price || 0;
const ma20 = item.ma20 || 0;
const ma50 = item.ma50 || 0;

let signal = 'HOLD';
let direction = 'NONE';

// Золотой крест (бычий сигнал)
if (ma20 > ma50 && price > ma20) {
  signal = 'BUY';
  direction = 'LONG';
}

// Медвежий крест
if (ma20 < ma50 && price < ma20) {
  signal = 'SELL';
  direction = 'SHORT';
}

if (signal === 'HOLD') {
  return [];
}

// Рассчитываем размеры позиции
const risk = settings.risk;
const stopLossPrice = direction === 'LONG' 
  ? price * (1 - risk.stop_loss_pct / 100)
  : price * (1 + risk.stop_loss_pct / 100);

const takeProfitPrice = direction === 'LONG'
  ? price * (1 + risk.take_profit_pct / 100)
  : price * (1 - risk.take_profit_pct / 100);

return {
  json: {
    ...item,
    _signal: signal,
    _direction: direction,
    _entryPrice: price,
    _stopLoss: stopLossPrice,
    _takeProfit: takeProfitPrice,
    _positionSizeUsdt: risk.position_size_usdt,
    _generatedAt: new Date().toISOString()
  }
};

